// Generated by OrchestKit Claude Plugin
// Created: 2026-05-12
// Issue: #1783 (M139 Bundle A — A1 agent-view title tagger)

/**
 * Unit tests for agent-view-titler hook.
 *
 * Covers:
 *  1. Named background agent → `[ork:<name>] <body>` shape, body capped at 40
 *  2. Anonymous prompt (no agent name) → first 50 chars, ellipsis on overflow
 *  3. Long prompt with newlines/whitespace → normalised on one line
 */

import { describe, it, expect, beforeEach } from 'vitest';
import type { HookInput } from '../../types.js';
import {
  agentViewTitler,
  deriveTitle,
  normalizePromptBody,
  truncateBody,
} from '../../subagent-start/agent-view-titler.js';
import { createTestContext } from '../fixtures/test-context.js';

function makeInput(overrides: Partial<HookInput> = {}): HookInput {
  return {
    tool_name: 'Task',
    session_id: 'test-session-1783',
    project_dir: '/test/project',
    tool_input: {},
    ...overrides,
  };
}

describe('agent-view-titler', () => {
  let testCtx: ReturnType<typeof createTestContext>;

  beforeEach(() => {
    testCtx = createTestContext();
  });

  // -------------------------------------------------------------------------
  // Case 1: Named background agent — title format correct
  // -------------------------------------------------------------------------

  describe('named agent', () => {
    it('formats [ork:<name>] <body> when subagent_type and prompt are set', () => {
      const input = makeInput({
        subagent_type: 'backend-system-architect',
        prompt: 'design the new auth middleware refactor strategy',
      });

      const result = agentViewTitler(input, testCtx);

      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      expect(result.hookSpecificOutput?.hookEventName).toBe('SubagentStart');

      const title = result.hookSpecificOutput?.sessionTitle ?? '';
      const prefix = '[ork:backend-system-architect] ';
      expect(title.startsWith(prefix)).toBe(true);
      const body = title.slice(prefix.length);
      // Body capped at 40 chars (+ at most 1 ellipsis char)
      expect(body.length).toBeLessThanOrEqual(41);
      expect(body.length).toBeGreaterThan(0);

      // additionalContext mirrors the title (defense-in-depth)
      expect(result.hookSpecificOutput?.additionalContext).toContain(title);
    });

    it('accepts agent_type as an alternative to subagent_type', () => {
      const input = makeInput({
        agent_type: 'data-pipeline-engineer',
        prompt: 'rebuild the ingest stage',
      });

      const title = deriveTitle(input);
      expect(title).toMatch(/^\[ork:data-pipeline-engineer\] /);
    });

    it('falls back to a tag-only title when the prompt is empty', () => {
      const input = makeInput({
        subagent_type: 'workflow-architect',
        prompt: '',
      });

      const title = deriveTitle(input);
      expect(title).toBe('[ork:workflow-architect]');
    });

    it('strips unsafe characters from the agent name to prevent title injection', () => {
      const input = makeInput({
        subagent_type: 'evil]name with spaces',
        prompt: 'do thing',
      });

      const title = deriveTitle(input);
      // Spaces and `]` stripped, leaving a sanitised identifier
      expect(title).toBe('[ork:evilnamewithspaces] do thing');
    });
  });

  // -------------------------------------------------------------------------
  // Case 2: Anonymous prompt — first-50-char fallback
  // -------------------------------------------------------------------------

  describe('anonymous prompt', () => {
    it('uses up to 50 chars of the prompt body when no agent name is set', () => {
      const shortPrompt = 'investigate the slow query path';
      const input = makeInput({ prompt: shortPrompt });

      const title = deriveTitle(input);
      expect(title).toBe(shortPrompt);
    });

    it('truncates long anonymous prompts with an ellipsis on a word boundary', () => {
      const longPrompt =
        'investigate the slow query path through the analytics layer and write up findings';
      const input = makeInput({ prompt: longPrompt });

      const title = deriveTitle(input);
      expect(title).not.toBeNull();
      expect(title!.length).toBeLessThanOrEqual(51); // 50 budget + 1 ellipsis char
      expect(title!.endsWith('…')).toBe(true);
      // No trailing punctuation/whitespace before the ellipsis
      expect(title!).not.toMatch(/[\s,;:.-]+…$/);
    });

    it('returns silent success when there is neither agent name nor prompt body', () => {
      const input = makeInput({ prompt: '' });

      const result = agentViewTitler(input, testCtx);

      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      // No sessionTitle should be emitted — let CC fall back to its default
      expect(result.hookSpecificOutput?.sessionTitle).toBeUndefined();
    });
  });

  // -------------------------------------------------------------------------
  // Case 3: Long prompt with newlines / whitespace — wraps cleanly
  // -------------------------------------------------------------------------

  describe('whitespace normalisation', () => {
    it('collapses newlines and tabs into single spaces', () => {
      const messy = 'line one\n\tline two\r\nline three     line four';
      const normalised = normalizePromptBody(messy);
      expect(normalised).toBe('line one line two line three line four');
    });

    it('drops ASCII control chars while preserving printable content', () => {
      // BEL (0x07), BS (0x08), VT (0x0b), FF (0x0c) — non-whitespace controls.
      // Build via String.fromCharCode so the source file stays plain ASCII.
      const bel = String.fromCharCode(7);
      const bs = String.fromCharCode(8);
      const vt = String.fromCharCode(11);
      const ff = String.fromCharCode(12);
      const messy = `hello${bel}world${bs}foo${vt}bar${ff}baz`;
      expect(normalizePromptBody(messy)).toBe('helloworldfoobarbaz');
    });

    it('produces a single-line title from a multiline prompt with whitespace runs', () => {
      const prompt =
        'Refactor the\n\n\tlong pipeline\r\nwith many   stages and check    every    invariant carefully';
      const input = makeInput({
        subagent_type: 'workflow-architect',
        prompt,
      });

      const result = agentViewTitler(input, testCtx);
      const title = result.hookSpecificOutput?.sessionTitle ?? '';

      // No control or wrap characters in the emitted title
      expect(title).not.toMatch(/[\n\r\t]/);
      // Tag intact
      expect(title.startsWith('[ork:workflow-architect] ')).toBe(true);
      // additionalContext also clean
      const ctxOut = result.hookSpecificOutput?.additionalContext ?? '';
      expect(ctxOut).not.toMatch(/[\n\r\t]/);
    });
  });

  // -------------------------------------------------------------------------
  // Helper coverage
  // -------------------------------------------------------------------------

  describe('truncateBody', () => {
    it('returns the input unchanged when within budget', () => {
      expect(truncateBody('short body', 40)).toBe('short body');
    });

    it('breaks on the last word boundary inside the budget when one exists', () => {
      const out = truncateBody('one two three four five six seven', 20);
      expect(out.endsWith('…')).toBe(true);
      expect(out.length).toBeLessThanOrEqual(21);
      // Truncation point landed on a space, then trailing whitespace was
      // trimmed before the ellipsis was appended.
      expect(out).toBe('one two three four…');
    });

    it('hard-cuts inside a word if no word boundary is present in the budget', () => {
      const out = truncateBody('supercalifragilisticexpialidocious', 10);
      expect(out.endsWith('…')).toBe(true);
      expect(out.length).toBeLessThanOrEqual(11);
    });
  });

  // -------------------------------------------------------------------------
  // Fail-open behaviour
  // -------------------------------------------------------------------------

  describe('fail-open', () => {
    it('returns silent success when the input shape is malformed', () => {
      // Pass a non-string prompt through the public hook entrypoint with a
      // hostile shape. Even if deriveTitle returns null, the hook must not
      // throw and must produce a HookResult shape CC can accept.
      const bad = {
        tool_name: 'Task',
        session_id: 'x',
        tool_input: {},
        prompt: { not: 'a string' },
      } as unknown as HookInput;

      const result = agentViewTitler(bad, testCtx);

      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });
  });
});
